    phases: {
      welcome: { duration: 5, title: "Body Parts Goalkeeping", description: "Coach throws soft balls gently at each child who tries to 'catch' it by trapping against their body (chest, stomach, knee). No using hands! Silly and fun — balls bouncing off tummies everywhere. Sets up the theme of body control." },
      warmup: { duration: 10, title: "Body Stop Exploration", description: "Children throw their own ball up gently and let it fall on different body parts — thigh, shin, stomach. Try to keep it from bouncing away. This is completely open exploration — coach celebrates every creative attempt.", activities: ["Toss ball up, catch on thigh", "Let ball fall onto shin", "Chest — let ball drop to feet", "Any creative body stop"] },
      positioning_game: { duration: 10, title: "Toss-Trap Pairs", description: "Pairs facing each other 3m apart. Child 1 gently tosses ball underarm to Child 2. Child 2 traps it against their body — thigh or stomach — then controls it to feet and passes back. Swap every 5 turns. Build height gradually.", coaching_points: ["Lean in to meet the ball", "Wrap the ball in — don't let it bounce off", "Bring it softly to your feet after the trap"] },
      game_training: { duration: 10, title: "Keeper Chaos", description: "Coach stands on a box or raised area and drops balls for children standing below. Children try to control the falling ball with thigh or chest before it bounces. Award a point if they control it within 2m. This is a high-engagement pure skill game.", coaching_points: ["Get under the ball", "Soft body — absorb the ball", "Immediately look for what to do next"] },
      big_game: { duration: 10, title: "3v3 Any Body", description: "3v3 game where the first touch can be any body part except hands. Encourages creative body control in game context. Coach praises any first touch that isn't just a kick.", coaching_points: ["Chest it down, then kick", "Thigh control opens up new angles", "Creativity with first touch is brilliant"] }
    },
