      warmup: { duration: 10, title: "Shadow Defending", description: "Pairs. Attacker walks/jogs anywhere. Defender must stay between attacker and a cone goal behind them. No tackling — just positioning. Progress to attacker being allowed to change direction suddenly. Defender learns to stay goal-side.", activities: ["Walk speed shadow defending", "Jog speed with direction changes", "Defender stays low and side-on", "Swap after 1 minute"] },
