      big_game: { duration: 10, title: "4v4 Defenders of the Galaxy", description: "4v4 normal game. Bibs awarded to best defenders of the session to wear in this game. Not a competition — just recognition of great defending efforts seen during session. Creates defending pride.", coaching_points: ["Defending is as heroic as scoring", "Team defends together", "Celebrate every clearance"] }
