      warmup: { duration: 10, title: "Turn & Dash", description: "Cones in a line. Children dribble toward cone, turn before reaching it (any turn — coach doesn't specify how), dash away. Progress to placing a defender-cone (passive obstacle) which they must turn away from.", activities: ["Dribble and U-turn at cone", "Dribble into pressure cone — turn and escape", "Turn and sprint to far end", "Try different turn techniques each run"] },
