      big_game: { duration: 10, title: "3v3 Turn & Score", description: "3v3 game. If a player receives with back to goal, turns a defender, and scores — it's worth 3 points. Normal goals worth 1. Creates incentive for a specific skill within open play.", coaching_points: ["Turn when you receive — don't just play it back", "Support the player on the ball", "Courage to turn under pressure"] }
