      positioning_game: { duration: 10, title: "Stop and Attack", description: "3v3. When a team wins the ball, coach calls 'ATTACK!' loudly. That team must immediately try to score. The other team must run back and defend their goal. This makes the transition concept dramatic and obvious.", coaching_points: ["Win the ball — think ATTACK!", "Lose the ball — sprint back!", "Transition is immediate — no standing still"] },
