      big_game: { duration: 10, title: "Proper Match", description: "Full MiniRoos format game with all rules applied: kick-in, corner kicks, kick-off after goals. Coach referees properly but with a smile. End with handshake and team cheer.", coaching_points: ["Follow the rules — they make the game great", "Respect the ref's decisions", "Handshake shows respect at the end"] }
